import{_ as n,r as o,o as s,c as i,a as e,b as a,d as r,e as d}from"./app-d1e08aba.js";const c={},l=e("h1",{id:"vcard",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#vcard","aria-hidden":"true"},"#"),a(" Vcard")],-1),h=e("h2",{id:"overview",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#overview","aria-hidden":"true"},"#"),a(" Overview")],-1),p=e("p",null,"With this extension, users can conveniently generate a VCard upon registering and after updating their profile. The process is made hassle-free as they can easily download the VCard.vcf file, ensuring that their contact information is readily available in a universally compatible format. This seamless integration not only simplifies the user experience but also provides a practical solution for sharing and storing contact details. Say goodbye to manual data entry and hello to efficiency with the automatic VCard generation feature.",-1),m=e("p",null,[e("strong",null,"Note: The VCard file must be generated by updating the User Profile. Until this update, there is no VCard file available.")],-1),u=e("strong",null,"Download:",-1),g={href:"https://github.com/ultimatemember/Extended/releases",target:"_blank",rel:"noopener noreferrer"},f=d(`<h2 id="setup" tabindex="-1"><a class="header-anchor" href="#setup" aria-hidden="true">#</a> Setup</h2><p>After activating the plugin, you must add the predefined field to the Profile Form. Edit the profile form by going to <strong>wp-admin&gt;Ultimate Member&gt;Forms&gt;Edit Profile Form</strong>. To add a field, click the plus <strong>&quot;+&quot;</strong> sign button in the form builder</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/6513c85de201484b1258ae1f/file-LmHFUveo2P.png" alt=""></p><p>Select <strong>VCard</strong> in the predefined fields from the fields manager and click the <strong>Update</strong> button to save changes</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/6513cab3556a3e3cf18cbea0/file-2OddUqkOzk.png" alt=""></p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/6513ccbd15e8de2d9d325e92/file-NLSTdSbrrs.png" alt=""></p><p>When a user registers or saves their profile, a <strong>VCard.vcf</strong> file is generated, and a VCard icon is shown in their profile allowing users to download the file. The VCard or.vcf file may be imported into the Contacts Application on <strong>Mac OS</strong>, <strong>Google Contacts</strong>, and <strong>Outlook on Windows OS</strong>.</p><p>The VCard field will appear or will be generated on the user&#39;s profile <strong>only when the user edits and updates</strong> their profile.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/6523ddcc42d97d1c045917dd/file-gAOrX5qqyr.png" alt=""></p><p>The sample image below is the downloaded Vcard from the site and imported in Google Contacts</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/6523dfc0ed8c6d2f1cffe2c3/file-8lGGe989Yu.png" alt=""></p><h3 id="action-hook" tabindex="-1"><a class="header-anchor" href="#action-hook" aria-hidden="true">#</a> Action hook</h3><p>You can use the action hook <code>um_vcard_before_save</code> to add extra fields to the VCard. See the example below:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>add_action(&#39;um_vcard_before_save&#39;,&#39;um_vcard_add_nickname&#39;, 10, 2 ); 
function um_vcard_add_nickname( $vcard_obj, $user_id ){    
   $vcard_obj-&gt;add( new Nickname( um_user(&#39;nickname&#39; ) ) ); 
}
   
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,14);function _(v,b){const t=o("ExternalLinkIcon");return s(),i("div",null,[l,h,p,m,e("p",null,[u,a(" In UM "),e("a",g,[a("Extended 2.0.3"),r(t)]),a(" under the Assets, click on the Source code(zip) to download the zip file.")]),f])}const x=n(c,[["render",_],["__file","1676-vcard.html.vue"]]);export{x as default};
